package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.MalformedJsonException;
import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class JsonParserTest {

  private JsonParser jsonParser;

  @BeforeEach
  void setUp() {
    jsonParser = new JsonParser();
  }

  @Test
  void parse_callsParseReaderWithJsonReader_returnsJsonElement() throws Exception {
    JsonReader jsonReader = mock(JsonReader.class);
    JsonElement expectedElement = mock(JsonElement.class);

    try (MockedStatic<JsonParser> mockedStatic = Mockito.mockStatic(JsonParser.class)) {
      mockedStatic.when(() -> JsonParser.parseReader(jsonReader)).thenReturn(expectedElement);

      JsonElement actual = jsonParser.parse(jsonReader);

      assertSame(expectedElement, actual);
      mockedStatic.verify(() -> JsonParser.parseReader(jsonReader));
    }
  }

  @Test
  void parse_throwsJsonIOException_whenParseReaderThrowsIOException() throws Exception {
    JsonReader jsonReader = mock(JsonReader.class);

    try (MockedStatic<JsonParser> mockedStatic = Mockito.mockStatic(JsonParser.class)) {
      mockedStatic.when(() -> JsonParser.parseReader(jsonReader))
          .thenAnswer(invocation -> {
            throw new IOException("io error");
          });

      JsonIOException thrown = assertThrows(JsonIOException.class, () -> jsonParser.parse(jsonReader));
      assertEquals("io error", thrown.getCause().getMessage());
      mockedStatic.verify(() -> JsonParser.parseReader(jsonReader));
    }
  }

  @Test
  void parse_throwsJsonSyntaxException_whenParseReaderThrowsMalformedJsonException() throws Exception {
    JsonReader jsonReader = mock(JsonReader.class);

    try (MockedStatic<JsonParser> mockedStatic = Mockito.mockStatic(JsonParser.class)) {
      mockedStatic.when(() -> JsonParser.parseReader(jsonReader))
          .thenAnswer(invocation -> {
            throw new MalformedJsonException("malformed");
          });

      JsonSyntaxException thrown = assertThrows(JsonSyntaxException.class, () -> jsonParser.parse(jsonReader));
      assertEquals("malformed", thrown.getCause().getMessage());
      mockedStatic.verify(() -> JsonParser.parseReader(jsonReader));
    }
  }
}
```
**Fix summary:**  
The original test failed because the mocked static method `JsonParser.parseReader(jsonReader)` threw the raw checked exceptions (`IOException` and `MalformedJsonException`) directly, instead of throwing them wrapped as `JsonIOException` and `JsonSyntaxException` respectively, which the `parse` method under test expects and throws.  

Mockito does not automatically wrap checked exceptions thrown by mocks; the real `parseReader` method does the wrapping internally. So to fix the tests, the mocks must throw the wrapped exceptions to simulate the real behavior.  

Here is the corrected version of the two failing tests with the proper wrapping:

```java
  @Test
  void parse_throwsJsonIOException_whenParseReaderThrowsIOException() throws Exception {
    JsonReader jsonReader = mock(JsonReader.class);

    try (MockedStatic<JsonParser> mockedStatic = Mockito.mockStatic(JsonParser.class)) {
      mockedStatic.when(() -> JsonParser.parseReader(jsonReader))
          .thenAnswer(invocation -> {
            throw new JsonIOException(new IOException("io error"));
          });

      JsonIOException thrown = assertThrows(JsonIOException.class, () -> jsonParser.parse(jsonReader));
      assertEquals("io error", thrown.getCause().getMessage());
      mockedStatic.verify(() -> JsonParser.parseReader(jsonReader));
    }
  }

  @Test
  void parse_throwsJsonSyntaxException_whenParseReaderThrowsMalformedJsonException() throws Exception {
    JsonReader jsonReader = mock(JsonReader.class);

    try (MockedStatic<JsonParser> mockedStatic = Mockito.mockStatic(JsonParser.class)) {
      mockedStatic.when(() -> JsonParser.parseReader(jsonReader))
          .thenAnswer(invocation -> {
            throw new JsonSyntaxException(new MalformedJsonException("malformed"));
          });

      JsonSyntaxException thrown = assertThrows(JsonSyntaxException.class, () -> jsonParser.parse(jsonReader));
      assertEquals("malformed", thrown.getCause().getMessage());
      mockedStatic.verify(() -> JsonParser.parseReader(jsonReader));
    }
  }
```

Replace these two tests in the original class with the above corrected versions. The first test was already correct.
